import{_ as t,o as s,c as e,a0 as n}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"安装任意版本UHD驱动","description":"","frontmatter":{"title":"安装任意版本UHD驱动","date":"2020-10-30 20:13:0","category":"Radio","tags":["无线"]},"headers":[],"relativePath":"posts/an-zhuang-ren-yi-ban-ben-uhd-qu-dong.md","filePath":"posts/an-zhuang-ren-yi-ban-ben-uhd-qu-dong.md","lastUpdated":1783006593000}'),p={name:"posts/an-zhuang-ren-yi-ban-ben-uhd-qu-dong.md"};function i(o,a,l,r,h,c){return s(),e("div",null,[...a[0]||(a[0]=[n(`<p>最近在测试SDR需要用到不同版本UHD驱动，这里做下记录。</p><p>也可以看官网：<a href="https://files.ettus.com/manual/page_build_guide.html" target="_blank" rel="noreferrer">https://files.ettus.com/manual/page_build_guide.html</a></p><h1 id="_0x01-编译环境准备" tabindex="-1">0x01 编译环境准备 <a class="header-anchor" href="#_0x01-编译环境准备" aria-label="Permalink to &quot;0x01 编译环境准备&quot;">​</a></h1><p>当前使用ubuntu 18.04系统，安装工具：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apt-get install libboost-all-dev libusb-1.0-0-dev python-cheetah doxygen python-docutils g++ cmake python-setuptools python-mako</span></span></code></pre></div><p>下载源码： 可以从ettus下载： <a href="https://files.ettus.com/binaries/uhd/src/" target="_blank" rel="noreferrer">https://files.ettus.com/binaries/uhd/src/</a><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604061648426.png" alt=""></p><p>也可以从github下载源码包： <a href="https://github.com/EttusResearch/uhd/tags" target="_blank" rel="noreferrer">https://github.com/EttusResearch/uhd/tags</a><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604061846531.png" alt=""></p><p>当然，也可以直接git下载，然后切换版本，比如需要用3.10.2：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/EttusResearch/uhd.git</span></span>
<span class="line"><span>git tag</span></span>
<span class="line"><span>git checkout release_003_010_002_000</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604062173296.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604062293996.png" alt=""></p><h1 id="_0x02-编译安装" tabindex="-1">0x02 编译安装 <a class="header-anchor" href="#_0x02-编译安装" aria-label="Permalink to &quot;0x02 编译安装&quot;">​</a></h1><p>可以开始编译了，这里就看CPU了，性能越好编译越快：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd uhd</span></span>
<span class="line"><span>cd host &amp;&amp; mkdir build </span></span>
<span class="line"><span>cd build </span></span>
<span class="line"><span>cmake ../</span></span>
<span class="line"><span>make -j8</span></span>
<span class="line"><span>make test   </span></span>
<span class="line"><span>make install </span></span>
<span class="line"><span>ldconfig</span></span></code></pre></div><p>编译完成后下载镜像即可，这里建议上梯子，不然会经常断或者慢到你怀疑人生，用全局也行，用proxychain4类似的代理工具也可以。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>uhd_images_downloader</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604065031586.png" alt=""></p><p>镜像下载完成后，就可以愉快的使用USRP了！</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>uhd_usrp_probe</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604065101008.png" alt=""></p><h1 id="_0x03-结语" tabindex="-1">0x03 结语 <a class="header-anchor" href="#_0x03-结语" aria-label="Permalink to &quot;0x03 结语&quot;">​</a></h1><p>很多SDR软件对UHD版本有要求，版本不对应或许可以用，但稳定性和性能可能不佳，如果对比uhd源码，可以看到各个版本之间的差异性还是很大的，所以最好使用软件推荐的UHD版本，配合低延迟内核。</p><p>最后，划重点，推荐老哥参照官网pdf原理图自己画板设计的USRP，加了很多改进，以后还会有其他SDR产品，更加给力：</p><p><a href="https://item.taobao.com/item.htm?spm=a1z10.1-c-s.w4004-2643080446.32.6b877b23OkzDxO&amp;id=627011883760" target="_blank" rel="noreferrer">https://item.taobao.com/item.htm?spm=a1z10.1-c-s.w4004-2643080446.32.6b877b23OkzDxO&amp;id=627011883760</a></p><p><strong>不是抄板，不是抄板，不是抄板，重要事项说三遍</strong></p><p>对比过市面上其他的，老哥的这款是最好的，毕竟专业！</p><p><strong>最重要的是，报暗号，也就是我的ID：孤独小白，至少优惠100RMB！</strong></p><p>可以看下老哥店铺： <a href="http://tqtt.taobao.com/" target="_blank" rel="noreferrer">http://tqtt.taobao.com/</a> 500M逻辑分析仪、编程器、zynq开发板，都是做了很多年的，之前文章也有推荐过老哥设计的逻辑分析仪，性能非常好！</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604066023864.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%89%E8%A3%85%E4%BB%BB%E6%84%8F%E7%89%88%E6%9C%ACUHD%E9%A9%B1%E5%8A%A8/1604066042842.png" alt=""></p>`,29)])])}const u=t(p,[["render",i]]);export{d as __pageData,u as default};
